ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
//(payload.Transactions[0].DataElements
  //  flatMap ((de) -> de.Rows flatMap ((r) -> r.Edits))
   // filter ((e) -> e.Name == "po_no")
   // map ((e) -> e.Value))[0] default ""
payload.Order.PoNo

%dw 2.0
output application/json
---
{
    method: Mule::p('p21.request.method.OData'),
    host: Mule::p('p21.request.host'),
    port: Mule::p('p21.request.port'),
    basePath: Mule::p('p21.request.basePath.Odata'),
    path: Mule::p('p21.request.path.ediOrderView'),

    headers: {
        "Authorization": "Bearer "++ (vars.accessToken default ""),
        "Content-Type": "application/json"
    },
    queryParams: {
    	"\$filter": "edi_x_ref_id eq '" ++ (vars.edixRefId default "") ++ "' and (po_no eq '" ++ (vars.poNumber default "") ++ "' or po_no eq null or po_no eq ' ')"
    },
    uriParams: {}
}

ee:message.ee:set-payload:
%dw 2.0
output application/xml
---
{
	Order @("xmlns:xsi": "http://www.w3.org/2001/XMLSchema-instance", "xmlns:xsd": "http://www.w3.org/2001/XMLSchema"): {
		CustomerId: payload.value[0].customer_id,
		CompanyId: 	payload.value[0].company_id,
		LocationId: payload.value.preferred_location_id[0],
		ShipToId:payload.value.ship_to_id[0],
		PoNo: vars.poNumber,
		ContactId: payload.value.edi_default_contact_id[0],
		Taker: vars.p21Request.Order.Taker default "MULESOFTINT",
		Notes: {
			OrderNote: {
				Topic: vars.p21Request.Order.Notes.OrderNote.Topic,
				Note: vars.p21Request.Order.Notes.OrderNote.Note,
				NotepadClassId: vars.p21Request.Order.Notes.OrderNote.NotepadClassId
			}
		},
		Lines: vars.p21Request.Order.Lines
	}
}

ee:variables.ee:set-variable:
%dw 2.0
output application/json

---
{
    method: Mule::p('p21.request.method.transaction'),
    host: Mule::p('p21.request.host'),
    port: Mule::p('p21.request.port'),
    basePath: Mule::p('p21.request.basePath.transaction1'),
    path: Mule::p('p21.request.path.coupaOrder'),

    headers: {
        "Authorization": "Bearer "++ (vars.accessToken default ""),
        "Content-Type": "application/xml"
    },
    queryParams: {},
    uriParams: {}
}
